sql:
SELECT air_flow_cfm 
FROM blower_performance 
WHERE orifice_size_in > 2.5;

SELECT model_name
FROM blower_models
WHERE model_id = 1;

SELECT performance_id, COUNT(DISTINCT metric_last_modified_by) AS unique_users
FROM performance_metrics
GROUP BY performance_id;

SELECT AVG(efficiency_percent) AS average_efficiency_2023
FROM blower_performance
WHERE strftime('%Y', test_date) = '2023';

SELECT model_id, model_name
FROM blower_models
WHERE strftime('%Y', production_start_date) > '2020';

external_knowledge:
- 'high vacuums' refer to a vacuum greater than 15 inches of water;
- 'specific test setting' means the environment with ID 1 and conducted by the operator with ID 1;
- 'given day' refers to '2023-05-02'.

- 'Config A' is a specific blower configuration for testing;
- 'Environment 1' refers to a unique testing environment setup;
- The 'beginning of the year' is January 1, 2023, in the context of this question.

sql:
SELECT AVG(air_power_w) AS average_air_power
FROM blower_performance
WHERE air_power_w BETWEEN 130 AND 150;

SELECT *
FROM blower_performance
INNER JOIN blower_models ON blower_performance.blower_model_id = blower_models.model_id;

SELECT bm.model_id, bm.model_name
FROM blower_models bm
ORDER BY bm.model_id ASC;

SELECT COUNT(config_id)
FROM blower_configurations
WHERE model_id IS NOT NULL;

SELECT COUNT(*)
FROM test_environments
WHERE environment_compliance_standards LIKE '%ISO 9001%';

external_knowledge:
- "gardeners and the keepers of the gate" refers to operators in their roles;
- "Facility B" is the location where the tests are conducted;
- "flowers have they watered" metaphorically means the number of performance tests conducted by each operator;
- "listed in order of their duties" refers to the order of roles in ascending order.

sql:
SELECT config_id, COUNT(*) AS num_tests
FROM performance_tests
GROUP BY config_id;
